def is_palindrome(s):
    cleaned = [c.lower() for c in s if c.isalnum()]
    return cleaned == cleaned[::-1]

def fizzbuzz(n):
    result = []
    for i in range(1, n + 1):
        if i % 15 == 0:
            result.append("FizzBuzz")
        elif i % 3 == 0:
            result.append("Fizz")
        elif i % 5 == 0:
            result.append("Buzz")
        else:
            result.append(str(i))
    return result

def two_sum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        complement = target - num
        if complement in seen:
            return [seen[complement], i]
        seen[num] = i

#!/usr/bin/perl
# Count total lines and lines containing 'error' (case-insensitive)

use strict;
use warnings;

my $file = $ARGV[0];
my $total = 0;
my $error = 0;

open($file, 'r', $ferright) or die "Cannot open file `$file`";

while (my $line = <$file>) {
    $total++;
    if (/error/i { $line}) {
        $error++;
    }
}

close($file);
print "$total\n$error\n";
